(1, 1, 2, '13800000002', 'student@stu.test.edu.cn', 'Java后端开发工程师', '计算机科学与技术专业本科在读，熟悉 Java、Spring Boot、MySQL 等技术，有完整项目开发经验，具备良好的工程习惯与团队协作能力。期望在杭州从事Java后端开发工程师相关工作。', '[{"school":"测试学院","major":"计算机科学与技术","degree":"本科","startDate":"2022-09","endDate":"2026-06","gpa":"3.35/4.0"}]', '[{"name":"计算机科学与技术综合实训 · MySQL实践项目","role":"负责人","startDate":"2025-03","endDate":"2025-07","description":"使用 MySQL、Linux、Spring Boot 搭建完整链路，独立完成核心模块设计与实现，项目在课程答辩中获评优秀，代码已开源。","skills":["MySQL","Linux","Spring Boot"]},{"name":"校园数据分析平台","role":"核心开发","startDate":"2024-09","endDate":"2025-01","description":"参与需求梳理与 Java、Git 相关模块开发，负责其中约 40% 的编码量。","skills":["Java","Git"]}]', '[{"company":"慧眼视觉科技有限公司","position":"Java后端开发工程师实习生","startDate":"2025-07","endDate":"2025-09","description":"参与线上业务模块迭代，独立承担 2 个需求的开发与自测，代码通过 Code Review 合入主干。"}]', '["“互联网+”大学生创新创业大赛校赛金奖","优秀学生干部","ACM-ICPC 省赛二等奖"]'),
